import numpy as np

def ctc_loss(log_probs: np.ndarray, targets: np.ndarray) -> float:
    T, num_classes = log_probs.shape
    L = len(targets)
    # Extended labels: [blank, t1, blank, t2, ..., blank]
    blank = 0
    ext = [blank]
    for t in targets:
        ext.append(t)
        ext.append(blank)
    ext = np.array(ext)  # length S = 2L+1
    S = len(ext)
    NEG_INF = -1e30
    # Alpha in log space: alpha[s] at each time step
    alpha = np.full((T, S), NEG_INF)
    # Initialization
    alpha[0, 0] = log_probs[0, ext[0]]
    if S > 1:
        alpha[0, 1] = log_probs[0, ext[1]]
    # Helper: log-sum-exp of two values
    def log_add(a, b):
        if a == NEG_INF:
            return b
        if b == NEG_INF:
            return a
        return max(a, b) + np.log1p(np.exp(-abs(a - b)))
    # Forward pass
    for t in range(1, T):
        for s in range(S):
            # Can come from s (stay)
            val = alpha[t-1, s]
            # Can come from s-1 (step forward)
            if s > 0:
                val = log_add(val, alpha[t-1, s-1])
            # Can come from s-2 (skip blank) if ext[s] != blank and ext[s] != ext[s-2]
            if s > 1 and ext[s] != blank and ext[s] != ext[s-2]:
                val = log_add(val, alpha[t-1, s-2])
            alpha[t, s] = val + log_probs[t, ext[s]]
    # Loss = -log(P(targets)) = -(log_add(alpha[T-1, S-1], alpha[T-1, S-2]))
    log_prob = alpha[T-1, S-1]
    if S >= 2:
        log_prob = log_add(log_prob, alpha[T-1, S-2])
    return float(-log_prob)
